from dataclasses import dataclass
from typing import Tuple

@dataclass
class SLOTarget:
    service: str
    sli_name: str
    target: float          # e.g. 0.995 for 99.5%
    window_days: int       # e.g. 30
    daily_task_volume: int # approximate tasks per day

    @property
    def error_budget_rate(self) -> float:
        return 1.0 - self.target

    @property
    def total_tasks_in_window(self) -> int:
        return self.daily_task_volume * self.window_days

    @property
    def allowed_failures(self) -> int:
        return int(self.total_tasks_in_window * self.error_budget_rate)

    @property
    def allowed_downtime_minutes(self) -> float:
        """Minutes of equivalent total-outage downtime in the window."""
        return self.window_days * 24 * 60 * self.error_budget_rate

    def remaining_budget(self, actual_failures: int) -> Tuple[int, float]:
        """Returns (remaining_failure_count, remaining_fraction)."""
        remaining = max(0, self.allowed_failures - actual_failures)
        fraction = remaining / self.allowed_failures if self.allowed_failures > 0 else 0.0
        return remaining, fraction

    def release_policy(self, remaining_fraction: float) -> str:
        if remaining_fraction > 0.50:
            return "APPROVE: budget healthy, releases OK"
        elif remaining_fraction > 0.20:
            return "CAUTION: extra testing required for risky releases"
        elif remaining_fraction > 0.0:
            return "FREEZE: reliability work only, no new feature releases"
        else:
            return "BREACH: SLO violated, exec escalation required"


if __name__ == "__main__":
    slo = SLOTarget(
        service="document-agent",
        sli_name="task_completion_rate",
        target=0.995,
        window_days=30,
        daily_task_volume=5000,
    )
    print(f"Service: {slo.service}")
    print(f"SLO: {slo.target:.1%} over {slo.window_days}d")
    print(f"Error budget rate: {slo.error_budget_rate:.3%}")
    print(f"Allowed failures: {slo.allowed_failures:,} tasks")
    print(f"Allowed downtime equivalent: {slo.allowed_downtime_minutes:.0f} min")
    print()

    # Simulate current state: 1,200 failures so far
    actual = 1200
    remaining, frac = slo.remaining_budget(actual)
    print(f"Actual failures this window: {actual:,}")
    print(f"Remaining budget: {remaining:,} failures ({frac:.1%})")
    print(f"Release policy: {slo.release_policy(frac)}")
